from neo4j.exceptions import CypherSyntaxError
from neo4j import GraphDatabase

driver = GraphDatabase.driver("bolt://localhost:7687", auth=("neo4j", "password"))

def validate_cypher(query: str) -> tuple[bool, str]:
    """
    Run EXPLAIN on the query to catch syntax errors without executing it.
    Returns (is_valid, error_message).
    """
    try:
        with driver.session() as session:
            session.run(f"EXPLAIN {query}").consume()
        return True, ""
    except CypherSyntaxError as e:
        return False, str(e)
    except Exception as e:
        return False, str(e)

def safe_cypher_chain(question: str, max_retries: int = 2) -> str:
    """Generate Cypher, validate, retry with error feedback if invalid."""
    schema = graph.get_schema
    for attempt in range(max_retries + 1):
        cypher = llm.invoke(
            CYPHER_GENERATION_PROMPT.format(schema=schema, question=question)
        ).content.strip()

        valid, error = validate_cypher(cypher)
        if valid:
            results = graph.query(cypher)
            return str(results)

        # Feed the error back to the LLM for correction
        question = (
            f"{question}\n\n"
            f"Previous attempt failed with: {error}\n"
            f"Failed Cypher: {cypher}\n"
            "Please fix the Cypher query."
        )
    return "Could not generate valid Cypher after retries."

import asyncio
from langchain_neo4j import GraphCypherQAChain
from langchain_openai import ChatOpenAI

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

async def hybrid_graph_retrieval(question: str, graph: Neo4jGraph) -> str:
    # Run both retrieval paths concurrently
    cypher_task = asyncio.create_task(
        asyncio.to_thread(
            GraphCypherQAChain.from_llm(
                llm=llm, graph=graph, allow_dangerous_requests=True
            ).invoke,
            {"query": question},
        )
    )
    vector_task = asyncio.create_task(
        asyncio.to_thread(vector_seed_expand, question, graph)
    )

    cypher_result, vector_triples = await asyncio.gather(
        cypher_task, vector_task, return_exceptions=True
    )

    # Collect context from both paths
    context_parts = []
    if isinstance(cypher_result, dict):
        context_parts.append("From structured query:\n" + str(cypher_result.get("result", "")))
    if isinstance(vector_triples, list):
        context_parts.append("From graph expansion:\n" + format_triples(vector_triples))

    combined_context = "\n\n".join(context_parts)

    answer_prompt = ChatPromptTemplate.from_messages([
        ("system", "Answer using the context below.\n\nContext:\n{context}"),
        ("human", "{question}"),
    ])
    return await (answer_prompt | llm).ainvoke(
        {"context": combined_context, "question": question}
    )
